	public void UpdateState(AnomalyGeneratorUserInterfaceState state)
	{
		_cooldownEnd = state.CooldownEndTime;
		_hasEnoughFuel = state.FuelCost <= state.FuelAmount;
		float value = Math.Clamp((float)state.FuelAmount / (float)state.FuelCost, 0f, 1f);
		((Range)FuelBar).Value = value;
		int num = state.FuelAmount / state.FuelCost;
		FuelText.Text = Loc.GetString("anomaly-generator-charges", new(string, object)[1] { ("charges", num) });
		UpdateTimer();
		UpdateReady();
	}

	public void UpdateTimer()
	{
		if (_timing.CurTime > _cooldownEnd)
		{
			CooldownLabel.SetMarkup(Loc.GetString("anomaly-generator-no-cooldown"));
			return;
		}
		TimeSpan timeSpan = _cooldownEnd - _timing.CurTime;
		string item = $"{timeSpan.Minutes:0}:{timeSpan.Seconds:00}";
		CooldownLabel.SetMarkup(Loc.GetString("anomaly-generator-cooldown", new(string, object)[1] { ("time", item) }));
		UpdateReady();
	}

	public void UpdateReady()
	{
		bool flag = _hasEnoughFuel && _timing.CurTime > _cooldownEnd;
		string markup = (flag ? Loc.GetString("anomaly-generator-yes-fire") : Loc.GetString("anomaly-generator-no-fire"));
		ReadyLabel.SetMarkup(markup);
		((BaseButton)GenerateButton).Disabled = !flag;
	}

	protected override void FrameUpdate(FrameEventArgs args)
	{
		//IL_0001: Unknown result type (might be due to invalid IL or missing references)
		((Control)this).FrameUpdate(args);
		UpdateTimer();
	}

